using System;
using System.IO;

class Program {
    static void Main() {
        File.WriteAllLines("/tmp/list.txt", new[] { "alpha", "beta", "gamma" });
        string[] lines = File.ReadAllLines("/tmp/list.txt");
        for (int i = 0; i < lines.Length; i++)
            Console.WriteLine($"{i+1}: {lines[i]}");
    }
}

using System;
