using System;
using System.IO;

class Program {
    static void Main() {
        using (var writer = new StreamWriter("/tmp/data.csv")) {
            writer.WriteLine("Name,Score");
            string[] names = { "Alice", "Bob", "Carol" };
            int[] scores = { 92, 85, 97 };
            for (int i = 0; i < names.Length; i++)
                writer.WriteLine($"{names[i]},{scores[i]}");
        }
        Console.Write(File.ReadAllText("/tmp/data.csv"));
    }
}

using System;
using System.IO;

class Program {
    static void Main() {
        File.WriteAllLines("/tmp/nums.txt", new[] { "1", "2", "3", "4", "5" });
        int sum = 0;
        using (var reader = new StreamReader("/tmp/nums.txt")) {
            string line;
            while ((line = reader.ReadLine()) != null) {
                sum += int.Parse(line);
            }
        }
        Console.WriteLine($"sum: {sum}");
    }
}

using System;
using System.IO;

class Program {
    static void Main() {
        string dir = "/tmp";
        string file = Path.Combine(dir, "data", "output.txt");
        Console.WriteLine(file);
        Console.WriteLine(Path.GetFileName(file));
        Console.WriteLine(Path.GetExtension(file));
        Console.WriteLine(Path.GetDirectoryName(file));
    }
}

using System;
using System.IO;

class Program {
    static void Main() {
        string dir = "/tmp/testio";
        Directory.CreateDirectory(dir);
        File.WriteAllText(Path.Combine(dir, "a.txt"), "a");
        File.WriteAllText(Path.Combine(dir, "b.txt"), "b");
        string[] files = Directory.GetFiles(dir, "*.txt");
        Array.Sort(files);
        foreach (var f in files)
            Console.WriteLine(Path.GetFileName(f));
        Directory.Delete(dir, recursive: true);
        Console.WriteLine(Directory.Exists(dir));
    }
}

using System;
using System.IO;

class Program {
    static void Main() {
        string path = "/tmp/meta.txt";
        File.WriteAllText(path, "test content");
        Console.WriteLine(File.Exists(path));
        var info = new FileInfo(path);
        Console.WriteLine($"size: {info.Length} bytes");
        Console.WriteLine($"readonly: {info.IsReadOnly}");
    }
}
